for (const key of Object.keys(ADDITIONS)) {
  for (const lang of Object.keys(LANGUAGES) as Lang[]) {
    t[lang][key] = ADDITIONS[key][lang] ?? ADDITIONS[key].en;
  }
}
// Per-language accessor with graceful fallback. Returns the requested
// language's string; if a key is missing for that language it falls back to
// English, and finally to the key name itself — so a not-yet-translated string
// never renders as `undefined`/blank during the multi-language rollout.
export function getT(lang: Lang): Record<string, string> {
  const base = t[lang] ?? t.en;
  return new Proxy(base, {
    get(target, prop) {
      if (typeof prop !== "string") return undefined;
      return target[prop] ?? t.en[prop] ?? prop;
    },
  }) as Record<string, string>;
}

export function detectBrowserLang(): Lang {
  if (typeof navigator === "undefined") return "en";
  const lang = navigator.language.slice(0, 2).toLowerCase();
  return (lang in LANGUAGES ? lang : "en") as Lang;
}
